import numpy as np

def cosine_similarity_matrix(E: np.ndarray) -> np.ndarray:
    norms = np.linalg.norm(E, axis=1, keepdims=True)
    E_norm = E / (norms + 1e-8)
    return E_norm @ E_norm.T

def deduplicate_memories(memories: list, embeddings: np.ndarray, threshold: float) -> tuple:
    n = len(memories)
    if n == 0:
        return [], np.empty((0, embeddings.shape[1])), []

    sim = cosine_similarity_matrix(embeddings)
    removed = set()

    for i in range(n):
        if i in removed:
            continue
        for j in range(i + 1, n):
            if j in removed:
                continue
            if sim[i, j] >= threshold:
                # Keep higher importance, remove lower
                imp_i = memories[i].get('importance', 0)
                imp_j = memories[j].get('importance', 0)
                if imp_i >= imp_j:
                    removed.add(j)
                else:
                    removed.add(i)
                    break  # i is removed, stop inner loop

    kept = [i for i in range(n) if i not in removed]
    deduped_memories = [memories[i] for i in kept]
    deduped_embeddings = embeddings[kept]
    return deduped_memories, deduped_embeddings, sorted(removed)
